import React, { useState } from 'react';

const AdminPanel = ({ rooms, archive, dailyLogs, threshold, setThreshold }) => {
    const [view, setView] = useState('stats'); // 'stats' или 'archive'

    const checkedCount = rooms.filter(r => r.status === 'checked').length;
    const dndCount = rooms.filter(r => r.status === 'dnd').length;
    const totalRooms = rooms.length;

    return (
        <div className="page-content fade-in">
            <h2 className="page-title">Management</h2>

            {/* Переключатель вкладок */}
            <div className="threshold-buttons" style={{ marginBottom: '25px' }}>
                <button className={`t-btn ${view === 'stats' ? 'active' : ''}`} onClick={() => setView('stats')}>СЕГОДНЯ</button>
                <button className={`t-btn ${view === 'archive' ? 'active' : ''}`} onClick={() => setView('archive')}>АРХИВ</button>
            </div>

            {view === 'stats' ? (
                <>
                    <div className="admin-stats-grid">
                        <div className="stat-card">
                            <span className="stat-value" style={{color: 'var(--success)'}}>{checkedCount}</span>
                            <span className="stat-label">Проверено</span>
                        </div>
                        <div className="stat-card">
                            <span className="stat-value" style={{color: 'var(--danger)'}}>{dndCount}</span>
                            <span className="stat-label">DND</span>
                        </div>
                    </div>

                    <div className="admin-settings-section">
                        <h3>Действия персонала (Live)</h3>
                        <div style={{ maxHeight: '250px', overflowY: 'auto' }}>
                            {dailyLogs.length === 0 ? (
                                <p style={{ fontSize: '12px', color: '#999', textAlign: 'center' }}>Сегодня еще никто не работал</p>
                            ) : (
                                dailyLogs.map((log, i) => (
                                    <div key={i} style={{ padding: '10px 0', borderBottom: '1px solid #eee', fontSize: '12px' }}>
                                        <span style={{ color: 'var(--gold)', fontWeight: '600' }}>{log.time}</span> —
                                        <b> {log.staff}</b>: номер <b>{log.roomId}</b> ({log.action})
                                    </div>
                                ))
                            )}
                        </div>
                    </div>
                </>
            ) : (
                <div className="admin-settings-section fade-in">
                    <h3>История за прошлые дни</h3>
                    {archive.length === 0 ? (
                        <p style={{ textAlign: 'center', color: '#999' }}>Архив пуст. Первый отчет появится завтра после 00:00</p>
                    ) : (
                        archive.map((item, idx) => (
                            <div key={idx} style={{ padding: '15px', border: '1px solid #eee', borderRadius: '8px', marginBottom: '10px' }}>
                                <div style={{ fontWeight: '600', marginBottom: '5px' }}>{item.date}</div>
                                <div style={{ fontSize: '12px', color: '#666' }}>
                                    ✅ {item.stats.checked} проверено | 🛑 {item.stats.dnd} DND
                                </div>
                            </div>
                        ))
                    )}
                </div>
            )}

            <div className="admin-settings-section" style={{ marginTop: '20px' }}>
                <h3 style={{ fontSize: '11px' }}>Настройка уведомлений: {threshold} дней</h3>
                <div className="threshold-buttons">
                    {[30, 60, 90, 180].map(d => (
                        <button key={d} className={`t-btn ${threshold === d ? 'active' : ''}`} onClick={() => setThreshold(d)}>{d}д</button>
                    ))}
                </div>
            </div>
        </div>
    );
};

export default AdminPanel;
